1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	};
15	
16	const FIRST_INSURANCE_RATE = 0.1;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	const LOYALTY_THRESHOLD_YEARS = 2;
19	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	function calculatePremiumParts(items: any[]): { policyBase: number; itemSurcharges: number } {
24	  const componentCounts: Record<string, number> = {};
25	  let policyBase = 0;
26	  let itemSurcharges = 0;
27	
28	  for (const item of items) {
29	    if (COMPONENT_TYPES.has(item.type)) {
30	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
31	    } else {
32	      const basePremium = BASE_PREMIUMS[item.type] || 0;
33	      policyBase += basePremium;
34	      if (item.cursed) {
35	        itemSurcharges += basePremium * CURSE_SURCHARGE_RATE;
36	      }
37	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
38	        itemSurcharges += basePremium * ENCHANTMENT_SURCHARGE_RATE;
39	      }
40	    }
41	  }
42	
43	  for (const type in componentCounts) {
44	    const count = componentCounts[type];
45	    if (count === BLOCK_SIZE) {
46	      policyBase += BLOCK_PREMIUM;
47	    } else {
48	      policyBase += count * COMPONENT_PREMIUM;
49	    }
50	  }
51	
52	  return { policyBase, itemSurcharges };
53	}
54	
55	export function processScenario(scenario: any): unknown {
56	  let quoteCount = 0;
57	  const results = scenario.steps.map((step: any) => {
58	    if (step.op === "quote") {
59	      const items = step.items || [];
60	      const { policyBase, itemSurcharges } = calculatePremiumParts(items);
61	      const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
62	        ? policyBase * LOYALTY_DISCOUNT_RATE
63	        : 0;
64	      const followUpDiscount = quoteCount > 0
65	        ? policyBase * FOLLOW_UP_DISCOUNT_RATE
66	        : 0;
67	      const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
68	      const premium = Math.ceil(policyBase + itemSurcharges - loyaltyDiscount - followUpDiscount + firstInsuranceSurcharge + PROCESSING_FEE);
69	      quoteCount++;
70	      return { premium };
71	    }
72	  });
